Create com.loanflow.loanservice.service.impl.LoanApplicationServiceImpl annotated with @Service. Each method must return a new response instance with placeholder values matching the API reference examples — not throw UnsupportedOperationException. This allows end-to-end response shape verification before business logic is added.

@Service
@RequiredArgsConstructor
public class LoanApplicationServiceImpl implements LoanApplicationService {

    @Override
    public CreateLoanApplicationResponse createApplication(CreateLoanApplicationRequest request, Long applicantUserId) {
        return CreateLoanApplicationResponse.builder()
            .applicationId(50021L)
            .status(LoanStatus.SUBMITTED)
            .submittedAt(Instant.now())
            .loanType(request.getLoanType())
            .amount(request.getAmount())
            .nextStep("UPLOAD_REQUIRED_DOCUMENTS")
            .build();
    }

    @Override
    public ApplicationDetailResponse getApplicationById(Long applicationId, Long requestingUserId, String requestingUserRole) {
        return ApplicationDetailResponse.builder()
            .applicationId(applicationId)
            .status(LoanStatus.UNDERWRITING_IN_PROGRESS)
            .loanType(LoanType.PERSONAL)
            .amount(new BigDecimal("25000"))
            .termMonths(48)
            .annualIncome(new BigDecimal("92000"))
            .submittedAt(Instant.now())
            .applicantDetails(ApplicantDetailsSummary.builder()
                .firstName("Devin")
                .lastName("Catuns")
                .email("devin@example.com")
                .build())
            .documentSummary(DocumentSummary.builder()
                .required(4).uploaded(4).verified(4)
                .build())
            .build();
    }

    @Override
    public ApplicationSearchResponse searchApplications(LoanStatus status, LoanType loanType, int page, int size, String sort) {
        return ApplicationSearchResponse.searchBuilder()
            .content(List.of())
            .page(page)
            .size(size)
            .totalElements(0L)
            .totalPages(0)
            .build();
    }

    @Override
    public UpdateApplicationStatusResponse updateStatus(Long applicationId, UpdateApplicationStatusRequest request, Long actingUserId) {
        return UpdateApplicationStatusResponse.builder()
            .applicationId(applicationId)
            .previousStatus(LoanStatus.SUBMITTED)
            .currentStatus(request.getStatus())
            .updatedAt(Instant.now())
            .reason(request.getReason())
            .build();
    }
}

